def format_greeting(name: str, title: str | None = None) -> str:
    if title is None:
        return f"Hello, {name}"
    return f"Hello, {title} {name}"

print(format_greeting("Alice"))        # Hello, Alice
print(format_greeting("Smith", "Dr.")) # Hello, Dr. Smith
